import string

def tamper_charencode(payload):
    """WAF bypass: URL-encode every character as %HH hex encoding.
    Preserves already-encoded sequences (%XX). Bypasses WAFs that
    match SQL keywords in cleartext without URL-decoding first."""
    if not payload:
        return payload
    result = []
    i = 0
    while i < len(payload):
        if (payload[i] == '%' and i + 2 < len(payload)
                and payload[i + 1] in string.hexdigits
                and payload[i + 2] in string.hexdigits):
            result.append(payload[i:i + 3])
            i += 3
        else:
            result.append('%%%.2X' % ord(payload[i]))
            i += 1
    return ''.join(result)

def tamper_charencode_double(payload):
    """Double URL-encoding: encode the percent signs themselves.
    Useful against WAFs that decode once but the backend decodes twice."""
    if not payload:
        return payload
    result = []
    for ch in payload:
        encoded = '%%%.2X' % ord(ch)
        double_enc = ''
        for c in encoded:
            double_enc += '%%%.2X' % ord(c)
        result.append(double_enc)
    return ''.join(result)

def tamper_charencode_unicode(payload):
    """IIS Unicode encoding variant: %u00XX format."""
    if not payload:
        return payload
    return ''.join('%%u00%.2X' % ord(c) for c in payload)

